const body = $json.body ?? $json;
const customerNo = String(body.customerNo ?? '').trim();
const startAtRaw = String(body.startAt ?? '').trim();
const endAtRaw = String(body.endAt ?? '').trim();
const customerQuestion = String(body.customerQuestion ?? '').trim();
const channel = String(body.channel ?? 'web-chat').trim();
const elasticsearchUrl = String(body.elasticsearchUrl ?? 'http://market-elasticsearch:9200/market-logs-2026.03.14/_search').trim();
const kibanaUrl = String(body.kibanaUrl ?? 'http://192.168.1.33:5601/').trim();
const llmUrlBase = String(body.llmUrl ?? 'http://192.168.1.8/v1').trim();
const llmModel = String(body.llmModel ?? 'qwen/qwen3.5-9b').trim();

function asIstanbulToUtc(value) {
  if (!value || !value.includes('T')) {
    throw new Error('Tarih alani gecersiz.');
  }

  const [datePart, timePart] = value.split('T');
  const [year, month, day] = datePart.split('-').map(Number);
  const [hour, minute] = timePart.split(':').map(Number);

  return new Date(Date.UTC(year, month - 1, day, hour - 3, minute, 0));
}

let llmUrl = llmUrlBase;
if (!llmUrl.endsWith('/chat/completions')) {
  llmUrl = llmUrl.replace(/\/$/, '') + '/chat/completions';
}

if (!customerNo) throw new Error('customerNo zorunludur.');
if (!startAtRaw || !endAtRaw) throw new Error('startAt ve endAt zorunludur.');

const startAt = asIstanbulToUtc(startAtRaw);
const endAt = asIstanbulToUtc(endAtRaw);

if (Number.isNaN(startAt.getTime()) || Number.isNaN(endAt.getTime())) {
  throw new Error('Tarih alanlari gecersiz.');
}

if (startAt > endAt) {
  throw new Error('Baslangic tarihi bitis tarihinden buyuk olamaz.');
}

return [{
  json: {
    customerNo,
    channel,
    customerQuestion,
    startAt: startAt.toISOString(),
    endAt: endAt.toISOString(),
    elasticsearchUrl,
    kibanaUrl,
    llmUrl,
    llmModel,
    query: {
      size: 50,
      sort: [{ '@timestamp': { order: 'desc' } }],
      query: {
        bool: {
          filter: [
            {
              range: {
                '@timestamp': {
                  gte: startAt.toISOString(),
                  lte: endAt.toISOString()
                }
              }
            }
          ],
          should: [
            { term: { 'user.id.keyword': customerNo } },
            { term: { 'user.id': customerNo } },
            { term: { 'customer_no.keyword': customerNo } },
            { term: { 'customer_no': customerNo } }
          ],
          minimum_should_match: 1
        }
      }
    }
  }
}];

const requestData = $('Istegi Hazirla').first().json;
const hits = $json.hits?.hits ?? [];
const rows = hits.map((hit) => hit._source ?? {});

const normalizedRows = rows.map((row) => ({
  timestamp: row['@timestamp'] ?? '-',
  userId: row.user?.id ?? row.customer_no ?? '-',
  level: row.log?.level ?? row.level ?? '-',
  action: row.event?.action ?? row.event_type ?? '-',
  outcome: row.event?.outcome ?? row.outcome ?? '-',
  message: String(row.message ?? '-').trim() || '-'
}));

const successCount = normalizedRows.filter((row) => row.outcome === 'success').length;
const failureCount = normalizedRows.filter((row) => row.outcome === 'failure' || row.level === 'ERROR' || row.level === 'WARN').length;
const latest = normalizedRows[0] ?? { action: '-', level: '-', message: '-' };
const lastFailure = normalizedRows.find((row) => row.outcome === 'failure' || row.level === 'ERROR' || row.level === 'WARN');
const latestMessages = normalizedRows.slice(0, 8).map((row) => row.message);
const detailedLogLines = normalizedRows.slice(0, 8).map((row) => `- Zaman: ${row.timestamp} | Olay: ${row.action} | Sonuc: ${row.outcome} | Mesaj: ${row.message}`);

let fallbackReply;
if (!normalizedRows.length) {
  fallbackReply = `Belirttiginiz zaman araliginda ${requestData.customerNo} icin bir kayit bulamadim. Isterseniz biraz daha genis bir saat araligi ile tekrar kontrol edebilirim.`;
} else {
  fallbackReply = `${requestData.customerNo} numarali musteriye ait hareketleri kontrol ettim. `;
  if (lastFailure) {
    fallbackReply += `Kayitlarda en son dikkat ceken sorun su mesaja yansiyor: ${lastFailure.message}. `;
  } else {
    fallbackReply += `Kayitlarda islemin devam ettigini gosteren mesajlar gorunuyor. `;
  }
  fallbackReply += `Musteriye teknik detay vermeden kisa ve net bir durum bilgilendirmesi donebilirsiniz.`;
}

const llmMessages = [
  {
    role: 'system',
    content: 'Sen bir musteri temsilcisi asistanisin. Sana verilen loglarda asil yorumlanacak alan message alanidir. Mesaj metinlerinden neden-sonuc cikart ve musteriye kibar, net, teknik olmayan Turkce cevap ver. ElasticSearch, Kibana, index, log, container, node gibi teknik terimleri asla kullanma.'
  },
  {
    role: 'user',
    content: [
      `Musteri numarasi: ${requestData.customerNo}`,
      `Kanal: ${requestData.channel}`,
      `Musteri sorusu: ${requestData.customerQuestion || 'Belirtilmedi'}`,
      '',
      'Onemli not: Asagidaki message alanlari birincil kanittir. Ozellikle message metinlerine bakarak yorum yap.',
      'Message alanlari:',
      ...latestMessages.map((line) => `- ${line}`),
      '',
      'Detayli log ozeti:',
      ...detailedLogLines,
      '',
      'Kurallar:',
      '- Sadece Turkce cevap ver.',
      '- Cevap en fazla 4 cumle olsun.',
      '- Musteriye net ve profesyonel cevap ver.',
      '- Teknik terim kullanma.',
      '- Sorunun muhtemel nedenini message metinlerinden cikar.',
      '- Eger kayit yoksa daha genis zaman araligi ile tekrar kontrol etmeyi oner.'
    ].join('\n')
  }
];

return [{
  json: {
    fallbackReply,
    llmUrl: requestData.llmUrl,
    llmModel: requestData.llmModel,
    llmMessages
  }
}];

const summary = $('Prompt ve Ozet Hazirla').first().json;
const modelReply = String($json.choices?.[0]?.message?.content ?? '').trim();
return [{
  json: {
    customerReply: modelReply || summary.fallbackReply
  }
}];
